    const user = userEvent.setup();
    render(<JargonText>The third alternative is key.</JargonText>);

    await user.hover(screen.getByText('third alternative'));

    await waitFor(() => {
      expect(screen.getByRole('tooltip')).toHaveTextContent(/§103/);
